const items = $input.all();
const results = [];
for (const item of items) {
  const subject = (item.json.subject || '').toLowerCase();
  const from = (item.json.from?.emailAddress?.address || item.json.from || '').toLowerCase();
  const body = item.json.bodyPreview || (item.json.body && item.json.body.content) || '';

  // Only process Anthropic login emails — match on subject OR sender domain
  const isAnthropicSender = from.includes('anthropic.com');
  const isLoginEmail = subject.includes('claude') || subject.includes('sign in') || subject.includes('secure link') || subject.includes('log in');
  if (!isAnthropicSender && !isLoginEmail) {
    continue;
  }

  // Extract the magic link URL from the email body.
  // Claude.ai sends a sign-in link like: https://claude.ai/login?token=...
  // or https://claude.ai/magic-link?... or similar OAuth callback URLs.
  const urlPatterns = [
    /https:\/\/claude\.ai\/[^\s"'<>\)]+/i,
    /https:\/\/[^\s"'<>\)]*anthropic\.com\/[^\s"'<>\)]+/i,
    /https:\/\/[^\s"'<>\)]*magic[^\s"'<>\)]+/i,
  ];
  let magicUrl = null;
  for (const pattern of urlPatterns) {
    const m = body.match(pattern);
    if (m) {
      // Clean up trailing punctuation that may have been included
      magicUrl = m[0].replace(/[.,;!?]+$/, '');
      break;
    }
  }

  if (magicUrl) {
    results.push({
      json: {
        url: magicUrl,
        subject: item.json.subject,
        from: from,
        timestamp: new Date().toISOString()
      }
    });
  }
}

if (results.length === 0) {
  return [];
}
return results;
